1	import type { PageLoad } from './$types'
2	import { createClient } from '$lib/gql/client'
3	import { gql } from 'graphql-request'
4	
5	const DOC_GRAPH_QUERY = gql`
6		query DocGraph {
7			docGraph {
8				rootDir
9				documents {
10					id
11					path
12					title
13					dependsOn
14					dependents
15				}
16				warnings
17				issues {
18					kind
19					path
20					id
21					message
22					relatedPath
23				}
24			}
25		}
26	`
27	
28	interface GraphDocument {
29		id: string
30		path: string
31		title: string
32		dependsOn: string[]
33		dependents: string[]
34	}
35	
36	export interface GraphIssue {
37		kind: string
38		path: string | null
39		id: string | null
40		message: string
41		relatedPath: string | null
42	}
43	
44	interface DocGraph {
45		rootDir: string
46		documents: GraphDocument[]
47		warnings: string[]
48		issues: GraphIssue[]
49	}
50	
51	interface DocGraphResult {
52		docGraph: DocGraph
53	}
54	
55	export const load: PageLoad = async ({ fetch }) => {
56		const client = createClient(fetch as unknown as typeof globalThis.fetch)
57		const data = await client.request<DocGraphResult>(DOC_GRAPH_QUERY)
58		const graph = data.docGraph
59		return {
60			graph: {
61				...graph,
62				issues: graph.issues ?? []
63			}
64		}
65	}
