266				<span class="text-body-sm text-fg-muted dark:text-dark-fg-muted">
267					{data.workers.totalCount} total
268				</span>
269				<button
270					type="button"
271					onclick={() => {
272						actionError = null;
273						showStartForm = !showStartForm;
274					}}
275					class="border border-accent-lever bg-accent-lever px-3 py-1.5 text-sm font-medium text-white hover:opacity-90 disabled:cursor-not-allowed disabled:opacity-60 dark:border-dark-accent-lever dark:bg-dark-accent-lever"
276				>
277					Start worker
278				</button>
279			</div>
280		</div>
281	
282		{#if showStartForm}
283			<form
284				class="grid gap-3 border border-border-line bg-bg-surface p-4 text-sm dark:border-dark-border-line dark:bg-dark-bg-surface sm:grid-cols-4"
