386								{edge.node.kind}
387							</td>
388							<td class="px-4 py-3">
389								<span
390									class="font-medium {stateClass(
391										livePhaseOverrides.get(edge.node.id) ?? edge.node.state
392									)}"
393								>
394									{livePhaseOverrides.get(edge.node.id) ?? edge.node.state}
395								</span>
396							</td>
397							<td class="px-4 py-3 font-mono-code text-mono-code text-fg-muted dark:text-dark-fg-muted">
398								{edge.node.currentBead ?? '—'}
