247	function isGraphQLEndpoint(input: Parameters<typeof globalThis.fetch>[0]): boolean {
248		if (typeof input === 'string') {
249			return new URL(input, globalThis.location?.href ?? 'http://localhost').pathname === '/graphql';
250		}
251		if (input instanceof URL) {
252			return input.pathname === '/graphql';
253		}
