257	async function requestBodyText(
258		input: Parameters<typeof globalThis.fetch>[0],
259		init?: Parameters<typeof globalThis.fetch>[1]
260	): Promise<string | null> {
261		if (typeof init?.body === 'string') {
262			return init.body;
263		}
264		if (input instanceof Request) {
265			return input.clone().text();
266		}
267		return null;
