277	function delegateInputFor(
278		input: Parameters<typeof globalThis.fetch>[0]
279	): Parameters<typeof globalThis.fetch>[0] {
280		if (typeof window === 'undefined' || !isGraphQLEndpoint(input)) {
281			return input;
282		}
283		if (typeof input === 'string' || input instanceof URL) {
284			return '/graphql';
