289	function withStaticPreviewFallback(fetchFn?: typeof globalThis.fetch): typeof globalThis.fetch {
290		const delegate = fetchFn ?? globalThis.fetch;
291		return async (input, init) => {
292			const delegateInput = delegateInputFor(input);
293			const response = await delegate(delegateInput, init);
294			if (response.status !== 404 || !isGraphQLEndpoint(input)) {
295				return response;
296			}
297	
298			const bodyText = await requestBodyText(input, init);
299			if (!bodyText) {
300				return response;
301			}
302	
303			let body: { query?: string };
304			try {
305				body = JSON.parse(bodyText) as { query?: string };
306			} catch {
307				return response;
308			}
309	
310			const data = body.query ? fallbackDataForQuery(body.query) : null;
311			return data ? fallbackGraphQLResponse(data) : response;
312		};
