111		ddxBinary = path.join(binDir, process.platform === 'win32' ? 'ddx-e2e.exe' : 'ddx-e2e');
112		const result = spawnSync('go', ['build', '-o', ddxBinary, '.'], {
113			cwd: CLI_DIR,
114			env: process.env,
115			encoding: 'utf8'
116		});
117		if (result.status !== 0) {
118			throw new Error(`failed to build ddx test binary\n${result.stdout}\n${result.stderr}`);
119		}
120		return ddxBinary;
