123	async function freePort(): Promise<number> {
124		return new Promise((resolve, reject) => {
125			const server = net.createServer();
126			server.once('error', reject);
127			server.listen(0, '127.0.0.1', () => {
128				const address = server.address();
129				if (!address || typeof address === 'string') {
130					server.close(() => reject(new Error('could not allocate port')));
131					return;
132				}
133				const port = address.port;
134				server.close(() => resolve(port));
135			});
136		});
137	}
