176	async function startRealDdxServer(fixtureRoot: string): Promise<RealServer> {
177		const port = await freePort();
178		const bin = ensureDdxBinary();
179		const child = spawn(bin, ['server', '--port', String(port), '--tsnet=false'], {
180			cwd: fixtureRoot,
181			env: {
182				...process.env,
183				DDX_NODE_NAME: 'graph-e2e-node',
184				XDG_DATA_HOME: path.join(fixtureRoot, '.xdg-data')
185			}
186		});
187		child.stdout.resume();
188		child.stderr.resume();
189		const baseURL = `https://127.0.0.1:${port}`;
190		const api = await playwrightRequest.newContext({ baseURL, ignoreHTTPSErrors: true });
191	
192		let lastError: unknown;
193		for (let i = 0; i < 80; i++) {
194			if (child.exitCode !== null) {
195				throw new Error(`ddx server exited early with code ${child.exitCode}`);
196			}
197			try {
198				const resp = await api.get('/api/health', { timeout: 500 });
199				if (resp.ok()) {
200					const infoResp = await api.post('/graphql', {
201						data: {
202							query: `query E2EProjectInfo {
203								nodeInfo { id name }
204								projects { edges { node { id name path } } }
205							}`
206						}
207					});
208					const payload = (await infoResp.json()) as {
209						data: {
210							nodeInfo: { id: string };
211							projects: { edges: Array<{ node: { id: string } }> };
212						};
213					};
214					const projectId = payload.data.projects.edges[0]?.node.id;
215					if (!projectId) throw new Error('ddx server returned no registered project');
216					return {
217						api,
218						nodeId: payload.data.nodeInfo.id,
219						projectId,
220						process: child,
221						root: fixtureRoot
222					};
223				}
224			} catch (err) {
225				lastError = err;
226			}
227			await new Promise((resolve) => setTimeout(resolve, 125));
228		}
229	
230		child.kill();
231		await api.dispose();
232		throw new Error(`ddx server did not become healthy: ${String(lastError)}`);
233	}
