235	async function stopRealDdxServer(server: RealServer) {
236		await server.api.dispose();
237		if (server.process.exitCode === null) {
238			server.process.kill();
239			await Promise.race([
240				new Promise((resolve) => server.process.once('exit', resolve)),
241				new Promise((resolve) => {
242					setTimeout(() => {
243						if (server.process.exitCode === null) server.process.kill('SIGKILL');
244						resolve(undefined);
245					}, 2000);
246				})
247			]);
248		}
249		fs.rmSync(server.root, { recursive: true, force: true });
250	}
