16	// DocumentByPath is the resolver for the documentByPath field.
17	// It reads the document at the given path (relative to the docgraph root or
18	// library) and returns its metadata plus raw file content.
19	func (r *queryResolver) DocumentByPath(ctx context.Context, path string) (*Document, error) {
20		if path == "" {
21			return nil, fmt.Errorf("path is required")
22		}
23	
24		cleaned, err := cleanDocumentPath(r.WorkingDir, path)
25		if err != nil {
26			return nil, err
27		}
28	
29		// Prefer the docgraph-tracked location: the documents list surfaces files
30		// walked under workingDir, so the detail view must read from the same root
31		// (otherwise the URL for a valid list entry 404s).
32		if graph, graphErr := docgraph.BuildGraphWithConfig(r.WorkingDir); graphErr == nil {
33			if id, ok := graph.PathToID[cleaned]; ok {
34				if d, ok := graph.Documents[id]; ok {
35					absPath := d.Path
36					if !filepath.IsAbs(absPath) {
37						absPath = filepath.Join(graph.RootDir, absPath)
38					}
39					if data, readErr := os.ReadFile(absPath); readErr == nil {
40						content := string(data)
41						doc := docToGQL(*d)
42						doc.Content = &content
43						return doc, nil
44					}
45				}
46			}
47		}
48	
49		// Fall back to the configured library path so documents created via the
50		// documentWrite mutation (which target the library) remain readable even
51		// when they have no DDx frontmatter and so do not appear in the graph.
52		cfg, err := config.LoadWithWorkingDir(r.WorkingDir)
53		if err != nil {
54			return nil, fmt.Errorf("loading config: %w", err)
55		}
56		if cfg.Library == nil || cfg.Library.Path == "" {
57			return nil, nil
58		}
59		libPath := cfg.Library.Path
60		if !filepath.IsAbs(libPath) {
61			libPath = filepath.Join(r.WorkingDir, libPath)
62		}
63	
64		fullPath := filepath.Join(libPath, cleaned)
65		data, err := os.ReadFile(fullPath)
66		if err != nil {
67			return nil, nil // not found → null
68		}
69		content := string(data)
70	
71		return &Document{
72			ID:         cleaned,
73			Path:       cleaned,
74			DependsOn:  []string{},
75			Inputs:     []string{},
76			Dependents: []string{},
77			Content:    &content,
78		}, nil
79	}
80	
81	func cleanDocumentPath(workingDir, path string) (string, error) {
82		cleaned := filepath.Clean(filepath.FromSlash(path))
83		if filepath.IsAbs(cleaned) {
84			rel, err := filepath.Rel(filepath.Clean(workingDir), cleaned)
85			if err != nil {
86				return "", fmt.Errorf("invalid path")
87			}
88			cleaned = rel
89		}
90		if cleaned == "." || filepath.IsAbs(cleaned) || cleaned == ".." ||
91			strings.HasPrefix(cleaned, ".."+string(filepath.Separator)) {
92			return "", fmt.Errorf("invalid path")
93		}
94		return cleaned, nil
95	}
