215	// DocGraphIssues is the resolver for the docGraphIssues field. It returns the
216	// same structured issue list used by the full graph query so dashboards can
217	// pull integrity state independently of the heavy graph payload.
218	func (r *queryResolver) DocGraphIssues(ctx context.Context) ([]*GraphIssue, error) {
219		graph, err := docgraph.BuildGraphWithConfig(r.WorkingDir)
220		if err != nil {
221			return nil, fmt.Errorf("building document graph: %w", err)
222		}
223		return issuesToGQL(graph.Issues), nil
224	}
225	
226	// issuesToGQL converts docgraph.GraphIssue values into the GraphQL model.
227	// Always returns a non-nil slice so downstream clients can treat an empty
228	// graph the same as a healthy one (no optional chaining required).
229	func issuesToGQL(issues []docgraph.GraphIssue) []*GraphIssue {
230		out := make([]*GraphIssue, 0, len(issues))
231		for _, issue := range issues {
232			gql := &GraphIssue{
233				Kind:    string(issue.Kind),
234				Message: issue.Message,
235			}
236			if issue.Path != "" {
237				p := issue.Path
238				gql.Path = &p
239			}
240			if issue.ID != "" {
241				id := issue.ID
242				gql.ID = &id
243			}
244			if issue.RelatedPath != "" {
245				rp := issue.RelatedPath
246				gql.RelatedPath = &rp
247			}
248			out = append(out, gql)
249		}
250		return out
251	}
