253	// docToGQL converts a docgraph.Document to the GraphQL Document model.
254	func docToGQL(d docgraph.Document) *Document {
255		doc := &Document{
256			ID:         d.ID,
257			Path:       d.Path,
258			Title:      d.Title,
259			DependsOn:  d.DependsOn,
260			Inputs:     d.Inputs,
261			Dependents: d.Dependents,
262			ParkingLot: d.ParkingLot,
263		}
264		if doc.DependsOn == nil {
265			doc.DependsOn = []string{}
266		}
267		if doc.Inputs == nil {
268			doc.Inputs = []string{}
269		}
270		if doc.Dependents == nil {
271			doc.Dependents = []string{}
272		}
273		if d.Prompt != "" {
274			p := d.Prompt
275			doc.Prompt = &p
276		}
277		if d.Review.ReviewedAt != "" || d.Review.SelfHash != "" {
278			depsJSON, _ := json.Marshal(d.Review.Deps)
279			doc.Review = &DocumentReview{
280				SelfHash:   d.Review.SelfHash,
281				Deps:       string(depsJSON),
282				ReviewedAt: d.Review.ReviewedAt,
283			}
284		}
285		if d.ExecDef != nil {
286			active := d.ExecDef.Active
287			required := d.ExecDef.Required
288			graphSource := true
289			doc.ExecDef = &DocumentExecDef{
290				ArtifactIds: d.ExecDef.ArtifactIDs,
291				Active:      &active,
292				Required:    &required,
293				GraphSource: &graphSource,
294			}
295		}
296		return doc
297	}
