function makeGraphResponse(
	docs = GRAPH_DOCS,
	warnings: string[] = [],
	issues: GraphIssueFixture[] = []
) {
	const pathToId: Record<string, string> = {};
	for (const doc of docs) {
		pathToId[doc.path] = doc.id;
	}
	return {
		docGraph: {
			rootDir: '/repos/alpha',
			documents: docs,
			pathToId: JSON.stringify(pathToId),
			warnings,
			issues
		}
	};
}
